# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self):
        self.db = sqlite3.connect('permissions.db')
        self.cursor = self.db.cursor()

    def check_permission(self, user, file):
        # Query the database to check if the user has permission to read the file
        self.cursor.execute("SELECT permission FROM permissions WHERE user=? AND file=?", (user, file))
        result = self.cursor.fetchone()
        return result[0] == 'read'

    def open_file(self, file):
        # Open the file and return its contents
        with open(file, 'r') as f:
            return f.read()

    def get_file_contents(self, user, file):
        if self.check_permission(user, file):
            return self.open_file(file)
        else:
            raise PermissionError("User does not have permission to read the file.")